<?php
/**
	 * Sorts a standard array of menu items into a nested structure keyed by the
	 * id of the parent menu.
	 *
	 * @since 5.9.0
	 *
	 * @param array $menu_items Menu items to sort.
	 * @return array An array keyed by the id of the parent menu where each element
	 *               is an array of menu items that belong to that parent.
	 */
function block_core_navigation_sort_menu_items_by_parent_id( $menu_items ) {
		$sorted_menu_items = array();
		foreach ( (array) $menu_items as $menu_item ) {
			$key = (int) $menu_item->ID;
			if ( empty( $menu_item->title ) ) {
				continue;
			}
			$sorted_menu_items[ $key ] = $menu_item;
		}
		unset( $menu_items, $menu_item );

		$menu_items_by_parent_id = array();
		foreach ( $sorted_menu_items as $menu_item ) {
			$parent_id = (int) $menu_item->menu_item_parent;
			if ( empty( $parent_id ) ) {
				$parent_id = 0;
			}
			$menu_items_by_parent_id[ $parent_id ][] = $menu_item;
		}

		return $menu_items_by_parent_id;
	}
```
